const express = require('express');
const app = express();

// --- Security Middleware ---

// Remove X-Powered-By header to avoid leaking framework info
app.disable('x-powered-by');

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Set basic security headers (consider using 'helmet' for production)
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('Content-Security-Policy', "default-src 'none'");
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  next();
});

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate and sanitize query parameters
  const limit = Math.min(Math.max(parseInt(req.query.limit, 10) || 10, 1), 100);
  const offset = Math.max(parseInt(req.query.offset, 10) || 0, 0);

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json(users.slice(offset, offset + limit));
});

// --- 404 Handler ---

app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Global Error Handler ---
// Express requires all 4 parameters to recognize this as an error handler
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Log the full error internally but never expose it to the client
  console.error('Unhandled error:', err);

  // Send a generic message — no stack traces, no internal details
  res.status(err.status || 500).json({
    error: 'Internal Server Error',
  });
});

// --- Server Startup ---

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

